33	  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
34	  it.todo("long-standing customer (≥2 years) gets 20% loyalty discount");
35	  it.todo("customer with exactly 2 years → loyalty discount applies");
36	  it.todo("first insurance carries 10% surcharge on policy base");
