53	  it.todo("damage to rune (250 G insurance), damage 200 G → payout 100 G");
54	
55	  // --- Claim: high enchantment clause ---
56	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");
57	
58	  // --- Claim: dragon material ---
59	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full, then deductible)");
60	
61	  // --- Claim: enchantment + dragon combined ---
62	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
63	  it.todo("dragon-material sword, ench exactly 8, damage 1000 G → payout 400 G");
64	
65	  // --- Deductible per damage event ---
